# decode_bitstream_to_pdf.py

def bitstream_to_bytes(bitstream: str) -> bytes:
    # Remove non-binary characters (optional)
    bitstream = ''.join(c for c in bitstream if c in '01')

    # Pad to full bytes if needed
    padded_length = len(bitstream) + (8 - len(bitstream) % 8) % 8
    bitstream = bitstream.ljust(padded_length, '0')

    byte_list = [
        int(bitstream[i:i + 8], 2)
        for i in range(0, len(bitstream), 8)
    ]
    return bytes(byte_list)

def save_to_pdf_file(byte_data: bytes, output_path: str):
    with open(output_path, 'wb') as f:
        f.write(byte_data)
    print(f"[✓] File saved to: {output_path}")

if __name__ == "__main__":
    # Paste your bitstream here (or load from a .txt)
    bitstream = (
        "..."
    )

    output_file = "decoded_output.pdf"
    byte_data = bitstream_to_bytes(bitstream)
    save_to_pdf_file(byte_data, output_file)
